def HSS(points, k: int, reference_point) -> np.ndarray:
    points = np.asarray(points)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D)")
    n, m = points.shape
    if k <= 0:
        return np.zeros((0, m))
    if k >= n:
        return points.copy()

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point)
    if reference_point.shape != (m,):
        raise ValueError("reference_point must have shape (D,) matching points' dimension")

    # Mask of selected points
    selected_mask = np.zeros(n, dtype=bool)
    selected_idx = []

    # Precompute single-point hypervolumes (useful for first selection and tie-breaking)
    single_hvs = np.empty(n, dtype=float)
    for i in range(n):
        single_hv = pg.hypervolume(points[[i], :]).compute(reference_point)
        single_hvs[i] = single_hv

    # Greedy selection: iteratively pick point with maximum marginal contribution
    # Keep current hypervolume of selected set to compute marginal contributions
    current_hv = 0.0
    selected_points = np.empty((0, m))

    for _ in range(k):
        best_idx = None
        best_gain = -np.inf

        # If no points selected yet, marginal gain is just single_hvs
        if len(selected_idx) == 0:
            # choose the point with max single hypervolume
            # tie-break randomly among equals for some diversity
            max_val = np.max(single_hvs[~selected_mask])
            candidates = np.where((single_hvs == max_val) & (~selected_mask))[0]
            if candidates.size > 1:
                best_idx = np.random.choice(candidates)
            else:
                best_idx = candidates[0]
            best_gain = single_hvs[best_idx]
        else:
            # Evaluate marginal gain for each unselected candidate
            # For efficiency, compute hv(selected ∪ {cand}) for each candidate
            # and take difference with current_hv
            # Note: we keep selected_points array and concatenate candidate
            for i in range(n):
                if selected_mask[i]:
                    continue
                cand_points = np.vstack([selected_points, points[i:i+1, :]])
                try:
                    hv_combined = pg.hypervolume(cand_points).compute(reference_point)
                except Exception:
                    hv_combined = 0.0
                gain = hv_combined - current_hv
                # Small numerical tolerance
                if gain > best_gain + 1e-12:
                    best_gain = gain
                    best_idx = i
                # early tie-break: if equal within tolerance, randomly choose with small prob
                elif abs(gain - best_gain) <= 1e-12 and best_idx is not None:
                    if np.random.rand() < 0.5:
                        best_idx = i

            # Fallback: if no gain was positive (all zero/negative due to numerics), pick the largest single hv remaining
            if best_idx is None:
                remaining = np.where(~selected_mask)[0]
                best_idx = remaining[np.argmax(single_hvs[remaining])]
                best_gain = single_hvs[best_idx]

        # Update selected set
        selected_mask[best_idx] = True
        selected_idx.append(best_idx)
        selected_points = np.vstack([selected_points, points[best_idx:best_idx+1, :]])
        # Update current_hv
        try:
            current_hv = pg.hypervolume(selected_points).compute(reference_point)
        except Exception:
            current_hv = 0.0

    # Return selected points in the order chosen
    subset = points[selected_idx, :]
    return subset

def HSS(points, k: int, reference_point) -> np.ndarray:
    import numpy as np
    import heapq

    points = np.asarray(points, dtype=float)
    if points.ndim != 2:
        raise ValueError("points must be a 2D array of shape (N, D)")
    N, D = points.shape

    if k <= 0:
        return np.zeros((0, D), dtype=float)

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1
    reference_point = np.asarray(reference_point, dtype=float)
    if reference_point.shape != (D,):
        raise ValueError("reference_point must have shape (D,)")

    # Helper: compute union volume of boxes anchored at ref with upper corners given by boxes (m, D)
    def union_boxes_volume(boxes, ref):
        boxes = np.asarray(boxes, dtype=float)
        if boxes.size == 0:
            return 0.0
        # Keep only boxes with positive volume: all coordinates > ref
        mask_pos = np.all(boxes > ref, axis=1)
        boxes = boxes[mask_pos]
        if boxes.shape[0] == 0:
            return 0.0

        def _union_recursive(bxs, r):
            if bxs.shape[0] == 0:
                return 0.0
            d = r.size
            if d == 1:
                max_end = np.max(bxs[:, 0])
                return max(0.0, max_end - r[0])
            coords = np.unique(np.concatenate(([r[0]], bxs[:, 0])))
            coords.sort()
            total = 0.0
            for i in range(len(coords) - 1):
                x_left = coords[i]
                x_right = coords[i + 1]
                if x_right <= x_left:
                    continue
                mask = bxs[:, 0] >= x_right
                if not np.any(mask):
                    continue
                sub_boxes = bxs[mask][:, 1:]
                sub_ref = r[1:]
                sub_vol = _union_recursive(sub_boxes, sub_ref)
                if sub_vol > 0.0:
                    total += (x_right - x_left) * sub_vol
            return total

        return float(_union_recursive(boxes, ref))

    # If k >= N, simply return all points
    if k >= N:
        return points.copy()

    # Precompute singleton volumes as upper bounds
    single_volumes = np.zeros(N, dtype=float)
    for i in range(N):
        single_volumes[i] = union_boxes_volume(points[i:i+1, :], reference_point)

    # Build max-heap of (bound, idx) using negative values because heapq is min-heap
    heap = []
    for i in range(N):
        # Use single-point volume as initial upper bound; can be zero
        heap.append((-single_volumes[i], i))
    heapq.heapify(heap)

    selected_indices = []
    selected_mask = np.zeros(N, dtype=bool)
    selected_boxes = np.zeros((0, D), dtype=float)
    current_volume = 0.0
    tol = 1e-12

    # Lazy greedy: pop top bound, compute true marginal; if still maximal, accept; else push updated bound
    while len(selected_indices) < k and heap:
        neg_bound, idx = heapq.heappop(heap)
        if selected_mask[idx]:
            continue  # already selected via some path
        # If the stored bound is essentially zero and current_volume > 0, quick-skip to avoid heavy computation
        bound = -neg_bound
        if bound <= 0.0 and current_volume > 0.0:
            true_gain = 0.0
        else:
            # compute union with candidate
            if selected_boxes.shape[0] == 0:
                vol_with = single_volumes[idx]
            else:
                combined = np.vstack((selected_boxes, points[idx:idx+1, :]))
                vol_with = union_boxes_volume(combined, reference_point)
            true_gain = vol_with - current_volume
            # numerical negative to zero
            if true_gain < 0 and true_gain > -1e-14:
                true_gain = 0.0

        # If heap is empty, accept if gain is non-negative (or if we still need points)
        if not heap:
            accept = True
        else:
            # Compare true_gain with next highest bound in heap (which is an upper bound for others)
            next_neg_bound = heap[0][0]
            next_best_bound = -next_neg_bound
            # If true_gain >= next_best_bound - tol, then this candidate is still the best
            accept = (true_gain >= next_best_bound - tol)

        if accept:
            # select this point (even if true_gain == 0, to fill up to k)
            selected_indices.append(idx)
            selected_mask[idx] = True
            if selected_boxes.shape[0] == 0:
                selected_boxes = points[idx:idx+1, :].copy()
            else:
                selected_boxes = np.vstack((selected_boxes, points[idx:idx+1, :]))
            # update current volume fully
            current_volume = union_boxes_volume(selected_boxes, reference_point)
        else:
            # update its bound to the true_gain and push back; it might still be chosen later
            # but if true_gain is negative due to numerical issues, clip to zero
            new_bound = max(0.0, true_gain)
            heapq.heappush(heap, (-new_bound, idx))

    # If we didn't select enough (e.g., all remaining gains are zero), fill arbitrarily with remaining unselected points
    if len(selected_indices) < k:
        for i in range(N):
            if not selected_mask[i]:
                selected_indices.append(i)
                selected_mask[i] = True
                if len(selected_indices) >= k:
                    break

    selected = points[np.array(selected_indices[:k], dtype=int), :]
    # Ensure shape exactly (k, D)
    if selected.shape[0] > k:
        selected = selected[:k, :]
    elif selected.shape[0] < k:
        if selected.shape[0] == 0:
            pad = np.tile(reference_point.reshape(1, -1), (k, 1))
            return pad
        extra = k - selected.shape[0]
        pad = np.repeat(selected[-1:, :], extra, axis=0)
        selected = np.vstack((selected, pad))
    return selected

def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    # 创建索引列表
    R_indices = list(range(n))
    R_objectives_array = points
    random.shuffle(R_indices)

    # 1. GSI算法 - 初始化
    S = set(R_indices[:k])
    elements_to_insert = R_indices[k:]

    # 2. GSI算法 - 迭代过程
    for element_to_add in elements_to_insert:
        S.add(element_to_add)

        worst_element_index = None
        min_contribution = float('inf')

        # 获取当前 S 的超体积
        if not S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        for s_index in list(S):
            # 尝试移除 s_index: S_temp = S - {s_index}
            S_temp = S - {s_index}

            # 移除后的超体积
            if not S_temp:
                M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                temp_selected = np.empty((0, M))
            else:
                temp_selected = R_objectives_array[list(S_temp)]

            if temp_selected.size == 0:
                hv_after_remove = 0.0
            else:
                try:
                    hv = pg.hypervolume(temp_selected)
                    hv_after_remove = hv.compute(reference_point)
                except Exception as e:
                    print(f"Hypervolume calculation error: {e}")
                    hv_after_remove = 0.0

            # 贡献度 = 移除前的 HV - 移除后的 HV
            contribution = current_hv - hv_after_remove

            if contribution < min_contribution:
                min_contribution = contribution
                worst_element_index = s_index

        if worst_element_index is not None:
            S.remove(worst_element_index)

    # 3. LS算法 - 初始化
    current_S = set(S)
    R_set = set(R_indices)

    if len(current_S) != k:
        raise ValueError("初始子集 S 的大小必须等于 k。")

    # 4. LS算法 - 迭代过程
    while True:
        # 获取当前 S 的超体积
        if not current_S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(current_S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        found_improvement = False

        R_minus_S = list(R_set - current_S)
        S_list = list(current_S)

        # 遍历所有可能的交换对 (s, r)
        for s_index in S_list:
            for r_index in R_minus_S:
                # 尝试交换: S' = S - {s_index} + {r_index}
                S_new = (current_S - {s_index}) | {r_index}

                # 计算新集合 S_new 的超体积
                if not S_new:
                    M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                    new_selected = np.empty((0, M))
                else:
                    new_selected = R_objectives_array[list(S_new)]

                if new_selected.size == 0:
                    new_hv = 0.0
                else:
                    try:
                        hv = pg.hypervolume(new_selected)
                        new_hv = hv.compute(reference_point)
                    except Exception as e:
                        print(f"Hypervolume calculation error: {e}")
                        new_hv = 0.0

                # 检查是否是改进
                if new_hv > current_hv:
                    current_S = S_new
                    found_improvement = True
                    break  # 跳出 r_index 循环

            if found_improvement:
                break  # 跳出 s_index 循环

        if not found_improvement:
            break

    # 5. 返回选择的点
    if not current_S:
        M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
        selected_points = np.empty((0, M))
    else:
        selected_points = R_objectives_array[list(current_S)]

    return selected_points
